@@ -0,0 +1,126 @@
+import { Type } from "@sinclair/typebox";
+import { getModel } from "/Users/badlogic/workspaces/pi-mono/packages/ai/src/models.js";
+import { complete } from "/Users/badlogic/workspaces/pi-mono/packages/ai/src/stream.js";
+import type { AssistantMessage, Context, ToolResultMessage, Usage } from "/Users/badlogic/workspaces/pi-mono/packages/ai/src/types.js";
+import { resolveApiKey } from "/Users/badlogic/workspaces/pi-mono/packages/ai/test/oauth.js";
+
+const model = getModel("openai-codex", "gpt-5.3-codex");
+
+const rawFullId =
+	"call_4VnzVawQXPB9MgYib7CiQFEY|";
+const normalizedFullId =
+	"call_4VnzVawQXPB9MgYib7CiQFEY|fc_I9b95oN1wD_cHXKTw3PpRkL6KkCtzTJhUxMouMWYwHeTo2j3htzfSk7YPx2vi";
+const controlFullId = "call_control123|fc_control123";
+
+const usage: Usage = {
+	input: 0,
+	output: 0,
+	cacheRead: 0,
+	cacheWrite: 0,
+	totalTokens: 0,
+	cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, total: 0 },
+};
+
+const editTool = {
+	name: "edit",
+	description: "Edit a file",
+	parameters: Type.Object({
+		path: Type.String(),
+		oldText: Type.Optional(Type.String()),
+		newText: Type.Optional(Type.String()),
+	}),
+};
+
+function makeAssistant(fullId: string, provider: "github-copilot" | "openai-codex", api: "openai-responses" | "openai-codex-responses"): AssistantMessage {
+	return {
+		role: "assistant",
+		content: [
+			{
+				type: "toolCall",
+				id: fullId,
+				name: "edit",
+				arguments: {
+					path: "src/styles/app.css",
+					oldText: "foo",
+					newText: "bar",
+				},
+			},
+		],
+		api,
+		provider,
+		model: "gpt-5.3-codex",
+		usage,
+		stopReason: "toolUse",
+		timestamp: Date.now() - 3000,
+	};
+}
+
+function makeToolResult(fullId: string): ToolResultMessage {
+	return {
+		role: "toolResult",
+		toolCallId: fullId,
+		toolName: "edit",
+		content: [{ type: "text", text: "Successfully replaced text in src/styles/app.css." }],
+		isError: false,
+		timestamp: Date.now() - 2000,
+	};
+}
+
+async function runCase(apiKey: string, name: string, assistant: AssistantMessage, toolCallId: string) {
+	const context: Context = {
+		systemPrompt: "You are concise.",
+		messages: [
+			{ role: "user", content: "Make a tiny edit.", timestamp: Date.now() - 4000 },
+			assistant,
+			makeToolResult(toolCallId),
+			{ role: "user", content: "Reply with exactly: ok", timestamp: Date.now() - 1000 },
+		],
+		tools: [editTool],
+	};
+
+	try {
+		const response = await complete(model, context, { apiKey, reasoningEffort: "low" });
+		const text = response.content.filter((b) => b.type === "text").map((b) => b.text).join("");
+		console.log(`\nCASE ${name}`);
+		console.log(
+			JSON.stringify(
+				{
+					stopReason: response.stopReason,
+					errorMessage: response.errorMessage ?? null,
+					text,
+				},
+				null,
+				2,
+			),
+		);
+	} catch (error) {
+		console.log(`\nCASE ${name}`);
+		console.log(
+			JSON.stringify(
+				{
+					threw: true,
+					error: error instanceof Error ? error.message : String(error),
+				},
+				null,
+				2,
+			),
+		);
+	}
+}
+
+async function main() {
+	const apiKey = await resolveApiKey("openai-codex");
+	if (!apiKey) {
+		throw new Error("No openai-codex OAuth token in ~/.pi/agent/auth.json");
+	}
+
+	await runCase(apiKey, "control_same_provider_short_id", makeAssistant(controlFullId, "openai-codex", "openai-codex-responses"), controlFullId);
+	await runCase(apiKey, "same_provider_normalized_session_id", makeAssistant(normalizedFullId, "openai-codex", "openai-codex-responses"), normalizedFullId);
+	await runCase(apiKey, "cross_provider_normalized_session_id", makeAssistant(normalizedFullId, "github-copilot", "openai-responses"), normalizedFullId);
+	await runCase(apiKey, "cross_provider_raw_session_id", makeAssistant(rawFullId, "github-copilot", "openai-responses"), rawFullId);
+}
+
+main().catch((error) => {
+	console.error(error instanceof Error ? error.message : String(error));
+	process.exitCode = 1;
+});

